#!/usr/bin/env python3
"""
CampusOne App Icon Generator (Python Version)
==============================================
This script generates all required iOS app icon sizes from a single source image.

Requirements:
    pip install Pillow

Usage:
    python3 generate_app_icons.py path/to/your/icon.png
"""

import os
import sys
import json
from pathlib import Path

try:
    from PIL import Image
except ImportError:
    print("Error: Pillow is not installed.")
    print("Install it with: pip3 install Pillow")
    sys.exit(1)


# Icon sizes needed for iOS
ICON_SIZES = [
    # iPhone Notification (iOS 7-15) 20pt
    (40, "Icon-App-20x20@2x.png"),
    (60, "Icon-App-20x20@3x.png"),
    
    # iPhone Settings (iOS 7-15) 29pt
    (58, "Icon-App-29x29@2x.png"),
    (87, "Icon-App-29x29@3x.png"),
    
    # iPhone Spotlight (iOS 7-15) 40pt
    (80, "Icon-App-40x40@2x.png"),
    (120, "Icon-App-40x40@3x.png"),
    
    # iPhone App (iOS 7-15) 60pt
    (120, "Icon-App-60x60@2x.png"),
    (180, "Icon-App-60x60@3x.png"),
    
    # iPad Notifications (iOS 7-15) 20pt
    (20, "Icon-App-20x20@1x.png"),
    
    # iPad Settings (iOS 7-15) 29pt
    (29, "Icon-App-29x29@1x.png"),
    
    # iPad Spotlight (iOS 7-15) 40pt
    (40, "Icon-App-40x40@1x.png"),
    
    # iPad App (iOS 7-15) 76pt
    (76, "Icon-App-76x76@1x.png"),
    (152, "Icon-App-76x76@2x.png"),
    
    # iPad Pro App (iOS 9-15) 83.5pt
    (167, "Icon-App-83.5x83.5@2x.png"),
    
    # App Store (iOS)
    (1024, "ItunesArtwork@2x.png"),
]

CONTENTS_JSON = {
    "images": [
        {"filename": "Icon-App-20x20@2x.png", "idiom": "iphone", "scale": "2x", "size": "20x20"},
        {"filename": "Icon-App-20x20@3x.png", "idiom": "iphone", "scale": "3x", "size": "20x20"},
        {"filename": "Icon-App-29x29@2x.png", "idiom": "iphone", "scale": "2x", "size": "29x29"},
        {"filename": "Icon-App-29x29@3x.png", "idiom": "iphone", "scale": "3x", "size": "29x29"},
        {"filename": "Icon-App-40x40@2x.png", "idiom": "iphone", "scale": "2x", "size": "40x40"},
        {"filename": "Icon-App-40x40@3x.png", "idiom": "iphone", "scale": "3x", "size": "40x40"},
        {"filename": "Icon-App-60x60@2x.png", "idiom": "iphone", "scale": "2x", "size": "60x60"},
        {"filename": "Icon-App-60x60@3x.png", "idiom": "iphone", "scale": "3x", "size": "60x60"},
        {"filename": "Icon-App-20x20@1x.png", "idiom": "ipad", "scale": "1x", "size": "20x20"},
        {"filename": "Icon-App-20x20@2x.png", "idiom": "ipad", "scale": "2x", "size": "20x20"},
        {"filename": "Icon-App-29x29@1x.png", "idiom": "ipad", "scale": "1x", "size": "29x29"},
        {"filename": "Icon-App-29x29@2x.png", "idiom": "ipad", "scale": "2x", "size": "29x29"},
        {"filename": "Icon-App-40x40@1x.png", "idiom": "ipad", "scale": "1x", "size": "40x40"},
        {"filename": "Icon-App-40x40@2x.png", "idiom": "ipad", "scale": "2x", "size": "40x40"},
        {"filename": "Icon-App-76x76@1x.png", "idiom": "ipad", "scale": "1x", "size": "76x76"},
        {"filename": "Icon-App-76x76@2x.png", "idiom": "ipad", "scale": "2x", "size": "76x76"},
        {"filename": "Icon-App-83.5x83.5@2x.png", "idiom": "ipad", "scale": "2x", "size": "83.5x83.5"},
        {"filename": "ItunesArtwork@2x.png", "idiom": "ios-marketing", "scale": "1x", "size": "1024x1024"},
    ],
    "info": {
        "author": "xcode",
        "version": 1
    }
}


def remove_alpha(image):
    """Remove alpha channel from image."""
    if image.mode in ('RGBA', 'LA') or (image.mode == 'P' and 'transparency' in image.info):
        # Create a white background
        background = Image.new('RGB', image.size, (255, 255, 255))
        
        # Convert image to RGBA if not already
        if image.mode != 'RGBA':
            image = image.convert('RGBA')
        
        # Paste the image on the white background
        background.paste(image, mask=image.split()[3])  # 3 is the alpha channel
        return background
    else:
        return image.convert('RGB')


def generate_icons(source_path, output_dir='AppIcon.appiconset'):
    """Generate all required icon sizes from source image."""
    
    # Check if source file exists
    if not os.path.exists(source_path):
        print(f"❌ Error: Source image '{source_path}' not found.")
        return False
    
    # Create output directory
    output_path = Path(output_dir)
    output_path.mkdir(exist_ok=True)
    
    print(f"✨ Starting icon generation...")
    print(f"📁 Source image: {source_path}")
    print(f"📁 Output directory: {output_dir}")
    print()
    
    try:
        # Open source image
        source_img = Image.open(source_path)
        print(f"📐 Source image size: {source_img.size}")
        
        # Remove alpha channel
        print("🔧 Removing alpha channel...")
        source_img = remove_alpha(source_img)
        
        # Generate each icon size
        print("🎨 Generating icon sizes...")
        generated = set()
        
        for size, filename in ICON_SIZES:
            if filename not in generated:  # Avoid duplicate work
                print(f"  → {filename} ({size}x{size}px)")
                
                # Resize with high quality
                resized = source_img.resize((size, size), Image.Resampling.LANCZOS)
                
                # Save as PNG
                output_file = output_path / filename
                resized.save(output_file, 'PNG', optimize=True)
                
                generated.add(filename)
        
        # Create Contents.json
        print("📝 Creating Contents.json...")
        contents_file = output_path / 'Contents.json'
        with open(contents_file, 'w') as f:
            json.dump(CONTENTS_JSON, f, indent=2)
        
        print()
        print("✅ Success! All icons generated.")
        print()
        print("📋 Next steps:")
        print(f"1. Copy the entire '{output_dir}' folder to:")
        print("   ios/CampusOne/Images.xcassets/")
        print()
        print("2. Your folder structure should be:")
        print("   ios/CampusOne/Images.xcassets/AppIcon.appiconset/")
        print()
        print("3. Open Xcode and verify the icons appear in the asset catalog")
        print()
        print("4. Clean build and create a fresh archive:")
        print("   - Product → Clean Build Folder")
        print("   - Product → Archive")
        print()
        print("5. Upload to App Store Connect")
        print()
        print(f"🎉 The icons are ready in the '{output_dir}' folder!")
        
        return True
        
    except Exception as e:
        print(f"❌ Error generating icons: {e}")
        import traceback
        traceback.print_exc()
        return False


def main():
    """Main function."""
    if len(sys.argv) < 2:
        print("❌ Error: No source image provided.")
        print()
        print("Usage:")
        print("  python3 generate_app_icons.py path/to/your/icon.png")
        print()
        print("Example:")
        print("  python3 generate_app_icons.py ~/Desktop/my-app-icon.png")
        sys.exit(1)
    
    source_path = sys.argv[1]
    success = generate_icons(source_path)
    
    sys.exit(0 if success else 1)


if __name__ == '__main__':
    main()
